:root {
  --color-card-bg: #ffffff;
  --color-header-bg: #1e1b4b;
  --color-header-text: #ffffff;
  --color-count-bg: #4338ca;
  --color-count-text: #e0e7ff;
  --color-border: #e2e8f0;
  --color-title: #1e293b;
  --color-author: #94a3b8;
  --color-track: #e2e8f0;
  --color-done: #22c55e;
  --color-reading: #6366f1;
  --color-done-label: #16a34a;
  --color-reading-label: #4338ca;
  --color-unread-label: #94a3b8;
  --color-spine-1: #f59e0b;
  --color-spine-2: #6366f1;
  --color-spine-3: #ef4444;
  --color-spine-4: #14b8a6;
  --color-footer-bg: #f8fafc;
  --color-stat-pill-bg: #f1f5f9;
  --color-stat-value: #1e293b;
  --color-stat-name: #64748b;
}

.bookshelf {
  background: var(--color-card-bg);
  border-radius: 16px;
  border: 1px solid var(--color-border);
  width: 480px;
  overflow: hidden;
}

.shelf-header {
  background: var(--color-header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 20px;
}

.shelf-title {
  color: var(--color-header-text);
  font-size: 16px;
  font-weight: 700;
}

.shelf-count {
  background: var(--color-count-bg);
  color: var(--color-count-text);
  font-size: 12px;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 20px;
}

.book-list {
  padding: 8px 0;
}

.book-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-bottom: 1px solid var(--color-border);
}

.book-item:last-child {
  border-bottom: none;
}

.book-spine {
  width: 8px;
  height: 44px;
  border-radius: 3px;
  background: var(--spine-color);
  flex-shrink: 0;
}

.book-info {
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex: 1;
  min-width: 0;
}

.book-title {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-title);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.book-author {
  font-size: 12px;
  color: var(--color-author);
}

.book-progress {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 4px;
  width: 110px;
  flex-shrink: 0;
}

.progress-bar {
  width: 100%;
  height: 6px;
  background: var(--color-track);
  border-radius: 99px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  width: var(--fill-pct);
  background: var(--fill-color);
  border-radius: 99px;
}

.progress-label {
  font-size: 11px;
  font-weight: 600;
}

.done-label {
  color: var(--color-done-label);
}

.reading-label {
  color: var(--color-reading-label);
}

.unread-label {
  color: var(--color-unread-label);
}

.shelf-footer {
  background: var(--color-footer-bg);
  border-top: 1px solid var(--color-border);
  display: flex;
  justify-content: center;
  gap: 10px;
  padding: 12px 20px;
}

.stat-pill {
  background: var(--color-stat-pill-bg);
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
}

.stat-value {
  font-size: 14px;
  font-weight: 700;
  color: var(--color-stat-value);
}

.stat-name {
  font-size: 12px;
  color: var(--color-stat-name);
}
